from collections import defaultdict
# quick parsers
def parse_supplier(path):
    txt=open(path).read()
    items=[]
    if path.endswith('.json'):
        data=json.loads(txt); return [(it['prod_id'], it['delivered_qty']) for it in data['items']]
    if path.endswith('.csv'):
        for row in csv.DictReader(txt.splitlines(), delimiter=';'):
            items.append((row['PRODUCT'], int(row['DELIVERED_QTY'])))
        return items
    # key-value or text
    if 'DELIVERED_QTY' in txt:
        for m in re.finditer(r'PRODUCT: (P_\d+) \| DELIVERED_QTY: (\d+)', txt): items.append((m.group(1), int(m.group(2))))
    else:
        for m in re.finditer(r'delivered (\d+) units of product (P_\d+)', txt): items.append((m.group(2), int(m.group(1))))
    return items
for d in [1,2]:
    total=0; byp=defaultdict(int)
    for fn in os.listdir('/app/raw_supplier_receipts'):
        if fn.startswith(f'day_{d:03d}_'):
            for p,q in parse_supplier('/app/raw_supplier_receipts/'+fn): total+=q; byp[p]+=q
    print('supplier total day',d,total,'by product P1-P5',[byp[f'P_{i}'] for i in range(1,6)])
    stotal=0
    for fn in os.listdir('/app/raw_wholesaler_store_receipts'):
        if fn.startswith(f'day_{d:03d}_'):
            txt=open('/app/raw_wholesaler_store_receipts/'+fn).read(); stotal+=int(re.search(r'TOTAL_DELIVERED_UNITS: (\d+)',txt).group(1))
    print('store total day',d,stotal)
